#include <bits/stdc++.h>
using namespace std;
const int N=500005;
int n,m,a[N],tr[N];
int query(int x)
{
	int sum=0;
	for(int i=x;i>0;i-=(i&(-i))) sum+=tr[i];
	return sum;
}
void add(int x,int k)
{
	for(int i=x;i<=n;i+=(i&(-i))) tr[i]+=k;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		add(i,a[i]-a[i-1]);
	}
	while(m--) 
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int x,y,k;
			cin>>x>>y>>k;
			add(x,k);
			add(y+1,-k);
		}
		else
		{
			int x;
			cin>>x;
			cout<<query(x)<<'\n';
		}
	}
	return 0;
}
